def main():
    with IN.open(encoding="utf-8", newline="") as f:
        reader = csv.DictReader(f)
        rows = list(reader)
        fieldnames = reader.fieldnames

    filled = 0
    for row in rows:
        pid = row["placement_id"]
        if pid in CONTENT:
            c = CONTENT[pid]
            row["traditional_meaning_ar"] = c["trad"]
            row["evolutionary_meaning_ar"] = c["evo"]
            row["developmental_task_ar"] = c["task"]
            row["key_references"] = c["refs"]
            row["status"] = "filled"
            filled += 1
        else:
            print(f"MISSING content for: {pid}")

    OUT.parent.mkdir(parents=True, exist_ok=True)
    with OUT.open("w", encoding="utf-8", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(rows)

    print(f"Wrote {filled} filled rows of {len(rows)} total to {OUT}")

    # Verify word counts and constraints
    issues = 0
    for row in rows:
        if row["status"] != "filled":
            continue
        text = " ".join([row["traditional_meaning_ar"], row["evolutionary_meaning_ar"], row["developmental_task_ar"]])
        word_count = len(text.split())
        if "—" in text:
            print(f"EM-DASH in {row['placement_id']}")
            issues += 1
        if "أنثروبوصوف" in text or "شتاينر" in text or "ستاينر" in text or "المسيح" in text:
            print(f"FORBIDDEN VOCAB in {row['placement_id']}")
            issues += 1
        if word_count < 200 or word_count > 360:
            print(f"WORD COUNT {word_count} in {row['placement_id']}")
    print(f"Issues: {issues}")


if __name__ == "__main__":
    main()
